# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
import numpy as np
import joblib
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import os

app = Flask(__name__)

# In-memory storage for labels and model
labels_storage = defaultdict(list)
model = None
label_encoder = LabelEncoder()
model_path = 'model.pkl'

@app.route('/label', methods=['POST'])
def add_label():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    labels_storage[image_id].append({
        'label': label,
        'annotator_id': annotator_id
    })
    
    return jsonify({'status': 'success'})

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated = {}
    for image_id, annotations in labels_storage.items():
        labels = [ann['label'] for ann in annotations]
        # Majority voting
        if labels:
            majority_label = Counter(labels).most_common(1)[0][0]
            aggregated[image_id] = majority_label
    
    return jsonify(aggregated)

@app.route('/train', methods=['POST'])
def train_model():
    global model
    
    # Get all aggregated labels
    aggregated = {}
    for image_id, annotations in labels_storage.items():
        labels = [ann['label'] for ann in annotations]
        if labels:
            majority_label = Counter(labels).most_common(1)[0][0]
            aggregated[image_id] = majority_label
    
    # Simple mock training - in reality, you'd load actual images
    # Here we simulate feature extraction with random data
    image_ids = list(aggregated.keys())
    labels = list(aggregated.values())
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(labels)
    
    # Mock features - in reality, you'd extract real image features
    features = np.random.rand(len(image_ids), 100)
    
    # Train model
    model = RandomForestClassifier(n_estimators=100, random_state=42)
    model.fit(features, encoded_labels)
    
    # Save model
    joblib.dump(model, model_path)
    
    return jsonify({'status': 'model trained successfully'})

@app.route('/predict', methods=['POST'])
def predict():
    global model
    
    if model is None:
        return jsonify({'error': 'No trained model available'}), 400
    
    # Mock feature extraction
    features = np.random.rand(1, 100)
    
    # Make prediction
    prediction = model.predict(features)
    predicted_label = label_encoder.inverse_transform(prediction)[0]
    
    return jsonify({'predicted_label': predicted_label})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)